+    #[fcp_async_core::runtime::test]
+    async fn test_tailscale_status_peers_method() {
+        let client = MockTailscaleClient::new();
+        let peer =
+            MockTailscaleClient::mock_peer("node-1", "host", "100.64.0.2".parse().unwrap(), &[]);
+        client.add_peer(peer).await;
